VALUES
  ('police-b20a8cf8-moex-00594', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '毒品危害防制條例第 32 條之 1 係為偵辦跨國性毒品犯罪組織而增訂之偵查方法，稱之為「控制 下交付」（ControlledDelivery），下列敘述何者正確？', '["刑事訴訟法第229條協助檢察官偵查之司法警察官，均得向最高檢察署提出偵查計畫書", "刑事訴訟法第230條受檢察官指揮之司法警察官，均得向高等檢察署提出偵查計畫書", "高等檢察署檢察長受理後，陳報最高檢察署檢察總長核可後，核發偵查指揮書，由入、出境管 制機關許可毒品及人員入出境", "最高檢察署檢察總長核可後，核發偵查指揮書，由入、出境管制相關機關許可毒品及人員入、 出境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00595', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於家庭暴力案件之逮捕或拘提規定，下列敘述何者正確？', '["警察人員發現家庭暴力罪之現行犯時，得逕行逮捕之", "警察人員逮捕家庭暴力罪之現行犯後，依刑事訴訟法第92條規定處理", "司法警察偵查犯罪認犯罪嫌疑人犯家庭暴力罪嫌疑重大，而情況急迫者，得逕行拘提之", "司法警察依家庭暴力防治法第29條第2項規定逕行拘提者，應於執行後24小時內報請檢察官 簽發拘票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00596', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於偵查涉外及跨境刑事案件之規定，下列敘述何者正確？', '["發現涉及國際刑事案件者，得請求內政部警政署國際組聯繫駐外單位及國外執法機構協助偵辦", "享有外交豁免權之人涉有犯罪嫌疑而無法確定身分者，得逕向外交部禮賓司特權科求證", "依法逮捕之一般外國人，於逮捕後，應於24小時內通知其本國駐華使領館或駐華機構", "逮捕大陸地區人民涉犯殺人案件，應自逮捕之時起24小時內傳真法務部及內政部警政署"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00001', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依我國憲法規定人民受逮捕拘禁時，逮捕拘禁機關至遲多久應移送該管法院審問？', '["48小時", "36小時", "24小時", "12小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00002', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依憲法及司法院大法官解釋，下列何者並非憲法上之法官？', '["檢察官", "地方法院簡易庭法官", "大法官", "懲戒法院法官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00003', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依司法院大法官解釋，大陸地區人民於臺灣地區設籍未滿 10 年者，不得擔任公務人員之規 定，並未牴觸憲法，下列敘述何者錯誤？', '["立法者制定規範時應斟酌事物本質的差異而為合理的區別對待，以實現憲法價值", "法律得基於原大陸地區人民對自由民主憲政體制的認識與其他臺灣人民可能不同，限制其 任公職之權利", "此類爭議涉及兩岸政治事務，故對於代表民意且充分掌握資訊的立法機關，司法機關應完 全尊重其決定", "設籍10年始得任公職的限制，仍在必要及合理的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00004', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '副總統缺位時，依憲法增修條文規定，應如何遞補？', '["由主要政黨提名候選人，交立法院補選", "由行政院院長兼任", "總統應於3個月內提名候選人，由立法院補選", "重新辦理副總統選舉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00005', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '關於憲法法庭，下列敘述何者錯誤？', '["憲法法庭之判決得不經言詞辯論", "憲法法庭之不受理裁定毋須標示主筆大法官", "憲法法庭之判決，應經全體大法官三分之二以上同意", "對於憲法法庭之裁判，不得聲明不服"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00006', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '下列何者是國民主權的直接具體表現？', '["立法委員之報酬或待遇，應以法律定之", "原住民族之地位與政治參與，應予以保障", "行政院院長由總統任命", "立法委員由人民選舉產生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00007', 'police-d442c1a4', 'police-d442c1a4-moex-114-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依司法院大法官解釋，下列何者並非修憲界限？', '["國民主權原則", "基本權保障", "權力分立原則", "租稅法定原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:06+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "510", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL)
